import java.io.*;

public class InsecureDeserializationExample {
    public static void main(String[] args) {
        try {
            String userInput = "serialized_data_here"; // This should be replaced with actual serialized data from user input

            ByteArrayInputStream bis = new ByteArrayInputStream(userInput.getBytes());
            ObjectInputStream ois = new ObjectInputStream(bis);

            Object obj = ois.readObject(); // Deserialize the object

            if (obj instanceof String) {
                String deserializedString = (String) obj;
                System.out.println("Deserialized string: " + deserializedString);
            } else {
                System.out.println("Invalid object type");
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

